CREATE VIEW dbo.stock01_por_talle_v AS SELECT dbo.articulos.cod_articulo, dbo.colores_por_articulo.cod_color_articulo, ISNULL(stock01.cantidad, 0) AS cantidad, dbo.rango_talles.posic_1 AS Talle, ISNULL(stock01.cant_1, 0) AS cant_1 FROM dbo.rango_talles INant_1 FROM dbo.rango_talles INNER JOIN dbo.articulos ON dbo.rango_talles.cod_rango = dbo.articulos.cod_rango LEFT OUTER JOIN (SELECT cod_almacen, cod_articulo, cod_color_articulo, cantidad, cant_6 FROM dbo.stock WHERE (cod_almacen = '01')) stock01 RIGHT O